1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	const CAP_MULTIPLIER = 2;
4	
5	type ItemCatalogEntry = { basePremium: number; insuranceValue: number };
6	
7	const ITEM_CATALOG: Record<string, ItemCatalogEntry> = {
8	  sword:     { basePremium: 100, insuranceValue: 1000 },
9	  amulet:    { basePremium:  60, insuranceValue:  600 },
10	  staff:     { basePremium:  80, insuranceValue:  800 },
11	  potion:    { basePremium:  40, insuranceValue:  400 },
12	  rune:      { basePremium:  25, insuranceValue:  250 },
13	  moonstone: { basePremium:  25, insuranceValue:  250 },
14	};
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Customer = { yearsWithMHPCO: number };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause: string; damages: Damage[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const catalogEntryFor = (item: Item): ItemCatalogEntry => {
26	  const entry = ITEM_CATALOG[item.type];
27	  if (entry === undefined) {
28	    throw new Error(`unknown item type: ${item.type}`);
29	  }
30	  return entry;
31	};
32	
33	const basePremiumFor = (item: Item): number => catalogEntryFor(item).basePremium;
34	
35	const COMPONENT_BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PREMIUM = 60;
37	
38	const sumBy = <T>(xs: T[], f: (x: T) => number): number =>
39	  xs.reduce((sum, x) => sum + f(x), 0);
40	
41	const groupBy = <T>(xs: T[], key: (x: T) => string): Map<string, T[]> => {
42	  const groups = new Map<string, T[]>();
43	  for (const x of xs) {
44	    const k = key(x);
45	    const group = groups.get(k) ?? [];
46	    group.push(x);
47	    groups.set(k, group);
48	  }
49	  return groups;
50	};
51	
52	const groupByType = (items: Item[]): Item[][] =>
53	  [...groupBy(items, (i) => i.type).values()];
54	
55	const basePremiumForGroup = (group: Item[]): number =>
56	  group.length === COMPONENT_BLOCK_SIZE
57	    ? COMPONENT_BLOCK_PREMIUM
58	    : sumBy(group, basePremiumFor);
59	
60	const totalBasePremium = (items: Item[]): number =>
61	  sumBy(groupByType(items), basePremiumForGroup);
62	
63	const CURSE_SURCHARGE_RATE = 0.5;
64	const HIGH_ENCHANTMENT_RATE = 0.3;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	const FIRST_INSURANCE_RATE = 0.1;
67	const LOYALTY_DISCOUNT_RATE = -0.2;
68	const LOYALTY_YEARS_THRESHOLD = 2;
69	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
70	
71	type PolicyContext = { customer: Customer; isFollowUp: boolean };
72	
73	const isCursed = (item: Item): boolean => item.cursed === true;
74	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
77	
78	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
79	
80	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
81	  sumBy(modifiers, ({ applies, rate }) => (applies(subject) ? rate : 0));
82	
83	const ITEM_SURCHARGES: Modifier<Item>[] = [
84	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
85	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
86	];
87	
88	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
89	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
90	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
91	
92	// First-insurance rate applies to every quote unconditionally;
93	// other policy modifiers are conditional on the customer/contract context.
94	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
95	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
96	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
97	];
98	
99	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
100	  baseTotal * (FIRST_INSURANCE_RATE + sumApplicableRates(POLICY_MODIFIERS, ctx));
101	
102	const itemSurchargeFor = (item: Item): number =>
103	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
104	
105	const itemSurchargesTotal = (items: Item[]): number =>
106	  sumBy(items, itemSurchargeFor);
107	
108	// MHPCO always rounds in its own favor: premiums round UP (customer pays more),
109	// payouts round DOWN (customer receives less).
110	const roundPremiumInOfficesFavor = Math.ceil;
111	const roundPayoutInOfficesFavor = Math.floor;
112	
113	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
114	  const baseTotal = totalBasePremium(items);
115	  return roundPremiumInOfficesFavor(
116	    baseTotal +
117	      itemSurchargesTotal(items) +
118	      policyAdjustment(baseTotal, ctx) +
119	      PROCESSING_FEE,
120	  );
121	};
122	
123	const insuranceValueFor = (item: Item): number => catalogEntryFor(item).insuranceValue;
124	
125	const insuranceSumFor = (items: Item[]): number => sumBy(items, insuranceValueFor);
126	
127	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
128	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
129	
130	const triggersHighEnchantmentClause = (item: Item): boolean =>
131	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
132	
133	const reimbursableAmount = (damage: Damage, item: Item): number =>
134	  triggersHighEnchantmentClause(item)
135	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : damage.amount;
137	
138	const payoutForDamage = (damage: Damage, item: Item): number =>
139	  reimbursableAmount(damage, item) - DEDUCTIBLE;
140	
141	const policyItemFor = (policy: QuoteStep, damage: Damage): Item =>
142	  policy.items.find((item) => item.type === damage.itemType)!;
143	
144	const capFor = (items: Item[]): number =>
145	  insuranceSumFor(items) * CAP_MULTIPLIER;
146	
147	const countBy = <T>(xs: T[], key: (x: T) => string): Map<string, number> => {
148	  const counts = new Map<string, number>();
149	  for (const x of xs) {
150	    const k = key(x);
151	    counts.set(k, (counts.get(k) ?? 0) + 1);
152	  }
153	  return counts;
154	};
155	
156	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
157	  const itemCounts = countBy(items, (i) => i.type);
158	  const damageCounts = countBy(damages, (d) => d.itemType);
159	  for (const [type, damageCount] of damageCounts) {
160	    const policyCount = itemCounts.get(type) ?? 0;
161	    if (policyCount === 0) {
162	      throw new Error(`claim references ${type} damage but the policy does not cover any ${type}`);
163	    }
164	    if (damageCount > policyCount) {
165	      throw new Error(`claim references more ${type} damages than the policy covers`);
166	    }
167	  }
168	};
169	
170	const claimResultFor = (
171	  step: ClaimStep,
172	  policy: QuoteStep,
173	  alreadyConsumed: number,
174	): { payout: number; remainingCap: number } => {
175	  const { damages } = step.incident;
176	  const { items } = policy;
177	  validateDamageCounts(damages, items);
178	  for (const damage of damages) {
179	    if (damage.amount < 0) {
180	      throw new Error(`damage amount must be non-negative: ${damage.amount}`);
181	    }
182	  }
183	  const desired = sumBy(damages, (damage) =>
184	    payoutForDamage(damage, policyItemFor(policy, damage)),
185	  );
186	  const remainingBefore = capFor(items) - alreadyConsumed;
187	  const payout = roundPayoutInOfficesFavor(Math.min(desired, remainingBefore));
188	  return { payout, remainingCap: remainingBefore - payout };
189	};
190	
191	const quoteResultFor = (step: QuoteStep, ctx: PolicyContext) => ({
192	  premium: premiumFor(step.items, ctx),
193	});
194	
195	const policyContextFor = (scenario: Scenario, stepIndex: number): PolicyContext => ({
196	  customer: scenario.customer,
197	  isFollowUp: stepIndex > 0,
198	});
199	
200	const policyReferencedBy = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
201	  scenario.steps[claim.policy] as QuoteStep;
202	
203	export const runScenario = (input: unknown): unknown => {
204	  const scenario = input as Scenario;
205	  const consumedCapByPolicy = new Map<number, number>();
206	  const results = scenario.steps.map((step, stepIndex) => {
207	    if (step.op === "quote") {
208	      return quoteResultFor(step, policyContextFor(scenario, stepIndex));
209	    }
210	    const policy = policyReferencedBy(scenario, step);
211	    const alreadyConsumed = consumedCapByPolicy.get(step.policy) ?? 0;
212	    const result = claimResultFor(step, policy, alreadyConsumed);
213	    consumedCapByPolicy.set(step.policy, alreadyConsumed + result.payout);
214	    return result;
215	  });
216	  return { results };
217	};
